/**
 * Contract Registry — single source of truth for every on-chain address.
 *
 * Every contract / wallet address the app references MUST appear here with
 * its role, status, chain, and a canonical explorer link generated by
 * chain-registry helpers. Do NOT duplicate address literals in components,
 * hooks, docs (outside DOCUMENTATION_AUTHORITY_MAP.md), or other libs.
 *
 * Status vocabulary:
 *   • LIVE     — deployed and integrated. Reads/writes safe per role.
 *   • DEPLOYED — on-chain but UI does not write to it yet.
 *   • PENDING  — not deployed. address MUST be null.
 *
 * Future contracts (e.g. SeatRecord721) MUST stay PENDING with address:null
 * until a real deployment tx hash is available. No placeholder strings,
 * no "0x000…", no inferred addresses.
 */

import { CONTRACTS, isLiveAddress, MEMBERSHIP_SALE_V2_CONTRACT_ADDRESS } from "./syndicate-config";
import { addressUrl, tokenUrl, contractUrl, CHAIN_REGISTRY } from "./chain-registry";

export type ContractRole =
  | "token"          // ERC-20
  | "stablecoin"     // ERC-20 stablecoin (USDC)
  | "sale"           // Membership Sale contract
  | "archive1155"    // SyndicateArchive1155
  | "seat-record-721"// future ERC-721
  | "lp-pair"        // Trader Joe LP pair
  | "wallet";        // public allocation wallet

export type ContractStatus = "LIVE" | "DEPLOYED" | "PENDING";

export type ContractEntry = {
  key: string;
  name: string;
  role: ContractRole;
  status: ContractStatus;
  /** Null when status is PENDING. */
  address: string | null;
  chainId: number;
  /** Canonical explorer link (token / address). Null when address is null. */
  explorerUrl: string | null;
  /** Where the ABI lives in source, when applicable. */
  abiSource?: string;
  /** Verification source link, when known. */
  verification?: string;
  /** One-line role description for docs / debug panels. */
  notes: string;
};

const chainId = CHAIN_REGISTRY.id;

function entry(
  key: string,
  name: string,
  role: ContractRole,
  status: ContractStatus,
  address: string | null,
  notes: string,
  abiSource?: string,
  verification?: string,
): ContractEntry {
  const explorerUrl =
    address && isLiveAddress(address)
      ? role === "token" || role === "stablecoin"
        ? tokenUrl(address)
        : role === "archive1155" || role === "sale" || role === "seat-record-721"
          ? contractUrl(address)
          : addressUrl(address)
      : null;
  return {
    key, name, role, status, address, chainId, explorerUrl, abiSource, verification, notes,
  };
}

