export function contractByKey(key: string): ContractEntry | undefined {
  return CONTRACT_REGISTRY.find((c) => c.key === key);
}

export function liveContracts(): ContractEntry[] {
  return CONTRACT_REGISTRY.filter((c) => c.status === "LIVE");
}

export function pendingContracts(): ContractEntry[] {
  return CONTRACT_REGISTRY.filter((c) => c.status === "PENDING");
}
